376	            let ids = alloc.record(spec.cell_count());
377	            let mut it = ids.ports.into_iter();
378	            let ports_prem: Vec<String> = (0..spec.premises.len()).map(|_| it.next().unwrap()).collect();
379	            let port_info = it.next().unwrap();
380	            let ports_concl: Vec<String> =
381	                (0..spec.conclusions.len()).map(|_| it.next().unwrap()).collect();
382	            let rec = build_record(&spec, &ports_prem, &port_info, &ports_concl);
383	            let stmt = Stmt::Node(Node::record(ids.node.clone(), rec));
384	            match &spec.cluster {
385	                Some(c) => {
386	                    let entry = clusters.entry(c.label.clone()).or_insert_with(|| {
387	                        cluster_order.push(c.label.clone());
388	                        (c.color.clone(), Vec::new())
389	                    });
390	                    entry.1.push(stmt);
391	                }
392	                None => free.push(stmt),
393	            }
394	            resolved.push(Resolved::Record { ports_prem, ports_concl, node: ids.node });
395	            continue;
396	        }
397	        let id = alloc.node();
398	        let stmt = match node {
399	            GraphNode::Knowledge { term, temporal } => {
400	                let label = format!("!KU( {} ) @ #{}", term, temporal);
401	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray")))
402	            }
403	            GraphNode::Action { fact, temporal } => {
404	                let label = format!("{} @ #{}", fact, temporal);
405	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue")))
406	            }
407	            GraphNode::Compressed { temporal, rule } => {
408	                let label = format!("#{} : {}", temporal, rule);
409	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label)))
410	            }
411	            GraphNode::Temporal { var } => {
412	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(format!("#{}", var))))
413	            }
414	            GraphNode::OpenTarget { node_var, premise_index } => {
415	                Stmt::Node(Node::shaped(id.clone(), Shaped::invtrapezium(node_var, *premise_index)))
416	            }
417	            GraphNode::Shaped { label, shape, color } => Stmt::Node(Node::shaped(
418	                id.clone(),
419	                Shaped { label: label.clone(), shape: shape.clone(), color: color.clone() },
420	            )),
421	            GraphNode::Rule(_) | GraphNode::RawRule(_) => unreachable!("records handled above"),
422	        };
423	        free.push(stmt);
424	        resolved.push(Resolved::Node(id));
425	    }
