427	    // Assemble: free nodes, then clusters (first-appearance order), then edges.
428	    let mut g = Graph::new(Header::Simple);
429	    for s in free {
430	        g.push(s);
431	    }
432	    for label in &cluster_order {
433	        let (color, body) = clusters.remove(label).unwrap();
434	        g.push(Stmt::Cluster(Cluster { label: label.clone(), color, body }));
435	    }
