// TEMPORARY dirty-room byte gate (round-8, unit B). Drives the clean RawRule
// seam (ported flat cells -> graph_clean::generate -> to_dot) and compares the
// record label byte-for-byte against fresh live HS captures. Not a durable test.

use tamarin_server::graph_clean::generate::{generate, GraphNode, RawRule, System};
use tamarin_server::graph_clean::to_dot;

fn record_line(dot: &str) -> String {
    dot.lines()
        .find(|l| l.contains("shape=\"record\""))
        .unwrap_or("<none>")
        .to_string()
}

// label="...": return the bytes between the first label=" and the closing ",fillcolor
fn label_of(rec: &str) -> String {
    let start = rec.find("label=\"").map(|i| i + 7).unwrap();
    let end = rec.find("\",fillcolor").unwrap();
    rec[start..end].to_string()
}

