#[test]
fn div_probe_clean_seam_vs_hs() {
    let vars = "aa.3, ab.3, ac.3, ad.3, ae.3, af.3, ag.3, ah.3, ai.3, aj.3, ak.3, al.3, am.3, an.3, ao.3, ap.3";
    let record = RawRule::new("#vr.2 : R16_10[Fire( )]", "#d5d897")
