// Scan the HS dot corpus for a concrete multi-cell FILL divergence: a prem/concl
// group where HS wraps a cell at a different element than the clean group_widths
// allocation + doclayout engine. Gated on GRAPHCLEAN_CORPUS.
fn split_top(s: &str, sep: char) -> Vec<String> {
    let ch: Vec<char> = s.chars().collect();
    let (mut parts, mut cur, mut depth, mut i) = (Vec::new(), String::new(), 0i32, 0usize);
    while i < ch.len() {
        let c = ch[i];
        if c == '\\' && i + 1 < ch.len() { cur.push(c); cur.push(ch[i + 1]); i += 2; continue; }
        match c {
            '{' => { depth += 1; cur.push(c); }
            '}' => { depth -= 1; cur.push(c); }
            _ if c == sep && depth == 0 => parts.push(std::mem::take(&mut cur)),
            _ => cur.push(c),
        }
        i += 1;
    }
    parts.push(cur);
    parts
}
fn unescape(t: &str) -> String {
    t.replace("\\<", "<").replace("\\>", ">").replace("\\{", "{").replace("\\}", "}").replace("\\|", "|")
}
fn parse_record(label: &str) -> Option<Vec<Vec<String>>> {
    if !(label.starts_with('{') && label.ends_with('}')) { return None; }
    let inner = &label[1..label.len() - 1];
    let mut groups = Vec::new();
    for g in split_top(inner, '|') {
        let g = g.trim();
        if !(g.starts_with('{') && g.ends_with('}')) { return None; }
        groups.push(split_top(&g[1..g.len() - 1], '|'));
    }
    Some(groups)
}
fn strip_port(cell: &str) -> Option<String> {
    let rest = cell.strip_prefix("<n")?;
    let sp = rest.find("> ")?;
    if !rest[..sp].chars().all(|c| c.is_ascii_digit()) { return None; }
    Some(rest[sp + 2..].to_string())
}
fn is_info_body(b: &str) -> bool { b.starts_with('#') && b.contains(" : ") }
fn dewrap(b: &str) -> String {
    let t = b.replace("&nbsp;", "").replace(",\\l", ", ").replace("\\l)", " )").replace("\\l", "");
    unescape(&t)
}

#[test]
fn corpus_fill_divergence_examples() {
    use tamarin_server::graph_clean::doclayout::wrap_cell_dot;
    use tamarin_server::graph_clean::generate::group_widths;
    let Ok(corpus) = std::env::var("GRAPHCLEAN_CORPUS") else {
        eprintln!("set GRAPHCLEAN_CORPUS to run"); return;
    };
    let mut shown = 0usize;
    let mut multi_total = 0usize;
    let mut multi_miss = 0usize;
    'files: for entry in std::fs::read_dir(&corpus).unwrap() {
        let path = entry.unwrap().path();
        if path.extension().and_then(|e| e.to_str()) != Some("dot") { continue; }
        let dot = std::fs::read_to_string(&path).unwrap();
        for line in dot.lines() {
            if !line.contains("shape=\"record\"") { continue; }
            let Some(ls) = line.find("label=\"") else { continue };
            let after = &line[ls + 7..];
            let Some(le) = after.find("\",fillcolor") else { continue };
            let Some(groups) = parse_record(&after[..le]) else { continue };
            for cells in &groups {
                let Some(bodies) = cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() else { continue };
                if bodies.len() < 2 || bodies.iter().any(|b| is_info_body(b)) { continue; }
                let flats: Vec<String> = bodies.iter().map(|b| dewrap(b)).collect();
                let widths: Vec<usize> = flats.iter().map(|f| f.chars().count()).collect();
                let alloc = group_widths(&widths);
                for (k, body) in bodies.iter().enumerate() {
                    if !body.contains("\\l") { continue; } // only wrapping cells
                    multi_total += 1;
                    let got = wrap_cell_dot(&flats[k], alloc[k] as isize);
                    if &got != body {
                        multi_miss += 1;
                        if got.contains("\\l") && shown < 4 { // fillErr: both wrap, break differs
                            shown += 1;
                            eprintln!("--- FILL DIVERGENCE #{shown} in {}", path.file_name().unwrap().to_string_lossy());
                            eprintln!("    group flats = {:?}", widths);
                            eprintln!("    cell[{k}] budget = {}", alloc[k]);
                            eprintln!("    flat = {}", flats[k]);
                            eprintln!("    HS   = {body}");
                            eprintln!("    clean= {got}");
                        }
                    }
                }
                if shown >= 4 && multi_total > 40000 { break 'files; }
            }
        }
    }
    eprintln!("multi-cell wrapping: {} miss / {} total = {:.2}% miss",
        multi_miss, multi_total, 100.0 * multi_miss as f64 / multi_total.max(1) as f64);
}

